}

// Implement the secure transaction handler protocol
class SecureBankingTransactionHandler: SecureTransactionHandler {
    private var bankingApp: BankingApp
    
    init(_ bankingApp: BankingApp) {
        self.bankingApp = bankingApp
    }
    
    func processTransaction(_ transaction: Transaction) {
        switch transaction.type {
        case .deposit:
            bankingApp.deposit(transaction.amount, for: transaction.id)
